    # The KV cache is quantized in FP8.
    FP8_KV_CACHE = auto()
    # FP8 QDQ
    FP8_QDQ = auto()
    # FP8 rowwise
    FP8_ROWWISE = auto()
    # FP8 block scales for Deepseek
    FP8_1x128_128x128 = auto()
    # W4A8 qserve
    W4A8_QSERVE = auto()
